import{_ as a,o as r,c as i,a2 as s}from"./chunks/framework.CH-YxFqP.js";const h=JSON.parse('{"title":"WireGuard","description":"","frontmatter":{},"headers":[],"relativePath":"reference/wireguard.md","filePath":"reference/wireguard.md","lastUpdated":1781350447000}'),d={name:"reference/wireguard.md"};function n(t,e,l,o,p,c){return r(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="wireguard" tabindex="-1">WireGuard <a class="header-anchor" href="#wireguard" aria-label="Permalink to &quot;WireGuard&quot;">​</a></h1><p>WireGuard Profile 由控制面板管理，可用于 Relay 或 L4 规则。</p><p>Profile 包含密钥、监听地址、接口地址、Peer、DNS、MTU、启用状态和标签。</p><p>敏感字段会在 API 和面板中脱敏显示。编辑时保持脱敏值不变，即可保留已存储的密钥。</p><h2 id="地址字段" tabindex="-1">地址字段 <a class="header-anchor" href="#地址字段" aria-label="Permalink to &quot;地址字段&quot;">​</a></h2><p>创建通用 WireGuard Profile 时，<code>Addresses</code> 表示 Agent 主机上 WireGuard UDP socket 的实际监听地址，例如 <code>192.168.0.109</code>；留空时默认监听 <code>0.0.0.0</code>。</p><p><code>WG 分配地址</code> 表示 WireGuard 接口地址或地址池，例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10.8.0.1/24</span></span>
<span class="line"><span>fd10:8::1/64</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>创建时可留空自动分配，之后可在面板中调整。</p><h2 id="自动地址池" tabindex="-1">自动地址池 <a class="header-anchor" href="#自动地址池" aria-label="Permalink to &quot;自动地址池&quot;">​</a></h2><p>自动分配地址池可通过 <code>NRE_WIREGUARD_AUTO_ADDRESS_POOLS</code> 配置，逗号分隔，同时支持 IPv4/IPv6：</p><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NRE_WIREGUARD_AUTO_ADDRESS_POOLS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=10.8.x.1/24,fd10:8:x::1/64</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="用于-relay" tabindex="-1">用于 Relay <a class="header-anchor" href="#用于-relay" aria-label="Permalink to &quot;用于 Relay&quot;">​</a></h2><p>Relay 监听器设置 <code>transport_mode=wireguard</code> 时，会使用所选 WireGuard Profile 作为 Relay 传输路径。Relay TLS、mux、认证仍然在 WireGuard 链路上生效。</p><h2 id="用于-l4" tabindex="-1">用于 L4 <a class="header-anchor" href="#用于-l4" aria-label="Permalink to &quot;用于 L4&quot;">​</a></h2><p>L4 规则设置 <code>listen_mode=wireguard</code> 时，客户端先连接目标 Agent 的 WireGuard UDP endpoint，进入隧道后再访问规则配置的虚拟服务 IP/端口。</p><p>L4 规则设置 <code>proxy_egress_mode=wireguard</code> 或选择 WireGuard 出口 Profile 时，TCP 代理入口的出站连接会通过所选 WireGuard Profile 发起。</p><p>如果需要配合 Cloudflare WARP，可使用可导出的标准 WireGuard profile，或在 Agent 主机外部运行 WARP 客户端并自行配置路由。内置 WireGuard 功能不负责 WARP 注册和自动轮换。</p>`,18)])])}const _=a(d,[["render",n]]);export{h as __pageData,_ as default};
